<?php
declare(strict_types=1);
require_once __DIR__ . '/../includes/app_models.php';
require_once __DIR__ . '/../includes/csrf.php';
csrf_start();
if (empty($_SESSION['admin'])) { header('Location: login.php'); exit; }
$flash=''; $errors=[];
function app_send_application_mail(string $to, string $subject, string $body): void { app_send_plain_mail($to, $subject, $body); }
if ($_SERVER['REQUEST_METHOD']==='POST') {
  if (!csrf_verify($_POST['csrf'] ?? '')) $errors[]='Ошибка безопасности.';
  else {
    $id=(int)($_POST['id'] ?? 0); $action=(string)($_POST['action'] ?? ''); $note=trim((string)($_POST['admin_note'] ?? ''));
    $stmt=db()->prepare('SELECT * FROM master_applications WHERE id=:id'); $stmt->execute([':id'=>$id]); $app=$stmt->fetch();
    if (!$app) $errors[]='Заявка мастера не найдена.';
    elseif ($action==='reject') { db()->prepare("UPDATE master_applications SET status='rejected', admin_note=:note WHERE id=:id")->execute([':note'=>$note ?: null, ':id'=>$id]); app_send_application_mail((string)$app['email'], 'Ответ по заявке мастера', "Здравствуйте, {$app['name']}!\n\nВаша заявка мастера была отклонена." . ($note ? "\nПричина/комментарий: {$note}" : '') . "\n\nС уважением, " . APP_NAME); $flash='Заявка отклонена, письмо отправлено если mail() работает на сервере.'; }
    elseif ($action==='accept') {
      $loginBase = preg_replace('/[^a-z0-9_]/i', '', strstr((string)$app['email'], '@', true) ?: 'master'); if ($loginBase==='') $loginBase='master';
      $login = strtolower($loginBase); $i=1; $check=db()->prepare('SELECT COUNT(*) FROM masters WHERE login=:login');
      do { $candidate = $i===1 ? $login : $login.$i; $check->execute([':login'=>$candidate]); $exists=(int)$check->fetchColumn(); $i++; } while($exists>0);
      $login=$candidate; $tempPass='m'.random_int(100000,999999);
      db()->prepare('INSERT INTO masters (login,password_hash,name,email,phone,photo,specialization,experience,work,brands,area,description,is_active) VALUES (:login,:password_hash,:name,:email,:phone,:photo,:specialization,:experience,:work,:brands,:area,:description,1)')->execute([':login'=>$login,':password_hash'=>password_hash($tempPass,PASSWORD_DEFAULT),':name'=>$app['name'],':email'=>$app['email'],':phone'=>$app['phone'],':photo'=>$app['photo'] ?: 'assets/img/masters/master-1.jpg',':specialization'=>$app['specialization'],':experience'=>$app['experience'],':work'=>$app['specialization'],':brands'=>$app['brands'] ?: null,':area'=>$app['area'] ?: null,':description'=>$app['description'] ?: null]);
      $masterId=(int)db()->lastInsertId(); db()->prepare("UPDATE master_applications SET status='accepted', admin_note=:note, created_master_id=:mid WHERE id=:id")->execute([':note'=>$note ?: null, ':mid'=>$masterId, ':id'=>$id]);
      app_send_application_mail((string)$app['email'], 'Вы приняты мастером на сайт', "Здравствуйте, {$app['name']}!\n\nВаша заявка принята.\nВход для мастера: /masters/index.php\nЛогин: {$login}\nВременный пароль: {$tempPass}\nПосле входа измените пароль в профиле.\n\nС уважением, " . APP_NAME);
      $flash='Мастер принят и добавлен на сайт. Логин: '.$login.' | временный пароль: '.$tempPass;
    }
  }
}
$filter=(string)($_GET['status'] ?? 'pending'); $allowed=['pending','accepted','rejected','all']; if(!in_array($filter,$allowed,true))$filter='pending';
$where=$filter==='all'?'':'WHERE status=:status'; $stmt=db()->prepare("SELECT * FROM master_applications $where ORDER BY id DESC"); $stmt->execute($filter==='all'?[]:[':status'=>$filter]); $apps=$stmt->fetchAll();
?><?php /* admin header */ ?>
