y-content:space-between;gap:14px;align-items:flex-start;margin-bottom:14px}.cardHead b{font-size:22px}.cardHead small{display:block;margin-top:5px;color:var(--muted);font-weight:800}.badge{display:inline-flex;border-radius:999px;padding:7px 10px;font-size:12px;font-weight:950}.new{background:rgba(37,99,235,.13);color:#1746a2}.in_work{background:rgba(37,99,235,.12);color:#1d4ed8}.done{background:rgba(22,163,74,.13);color:#15803d}.cancelled{background:rgba(220,38,38,.12);color:#b91c1c}.formGrid{display:grid;grid-template-columns:1fr 1fr;gap:12px}.wide{grid-column:1/-1}label{display:grid;gap:7px;color:#475467;font-size:12px;text-transform:uppercase;letter-spacing:.04em;font-weight:950}input,select,textarea{width:100%;font:inherit;border:1px solid var(--line);border-radius:12px;padding:10px 12px;background:#fff;color:var(--dark);outline:none}textarea{min-height:84px;resize:vertical}.btn{border:0;border-radius:12px;padding:10px 13px;font-weight:950;cursor:pointer;display:inline-flex;align-items:center;justify-content:center}.save{background:var(--dark);color:#fff}.delete{background:rgba(220,38,38,.11);color:#b91c1c}.soft{background:#fff;border:1px solid var(--line)}.assign{background:rgba(37,99,235,.10);color:#1d4ed8}.actions{display:flex;gap:8px;flex-wrap:wrap}.miniLine{display:flex;gap:10px;flex-wrap:wrap;align-items:center;margin:10px 0;color:#667085;font-weight:800;font-size:13px}.pill{display:inline-flex;gap:6px;align-items:center;border:1px solid var(--line);border-radius:999px;background:#fbfbfd;padding:7px 10px}.empty{padding:28px;text-align:center}.tableWrap{overflow:auto;background:#fff;border:1px solid var(--line);border-radius:24px;box-shadow:var(--shadow)}table{width:100%;border-collapse:collapse;min-width:980px}th,td{padding:14px;border-bottom:1px solid var(--line);text-align:left;vertical-align:top}th{font-size:12px;text-transform:uppercase;letter-spacing:.06em;color:#475467;background:#fbfbfd}.avatar{width:82px;height:82px;border-radius:22px;object-fit:cover;object-position:center 18%;border:1px solid var(--line);background:#f0fdf8}.profileRow{display:flex;gap:12px;align-items:center}.profileRow strong{display:block}.profileRow span{display:block;color:var(--muted);font-size:12px;font-weight:800}.sideBy{display:grid;grid-template-columns:1fr .75fr;gap:16px}.loginBox{max-width:460px;margin:8vh auto;padding:26px;background:#fff;border:1px solid var(--line);border-radius:28px;box-shadow:var(--shadow)}@media(max-width:1000px){.grid,.sideBy{grid-template-columns:1fr}.stats{grid-template-columns:repeat(2,1fr)}.top__row,.hero{display:block}.nav{margin-top:12px}.formGrid{grid-template-columns:1fr}.wide{grid-column:auto}}@media(max-width:540px){.stats{grid-template-columns:1fr}.hero h1{font-size:31px}.container,.top__row{width:min(100% - 20px,1320px)}}
